query:
ALTER TABLE blog_posts 
  ADD COLUMN tags TEXT DEFAULT NULL,
  ADD COLUMN reading_time INT NOT NULL DEFAULT 5,
  ADD COLUMN view_count INT NOT NULL DEFAULT 0,
  ADD COLUMN published ENUM('draft','published','scheduled') NOT NULL DEFAULT 'published',
  ADD COLUMN scheduled_at TIMESTAMP NULL DEFAULT NULL;

UPDATE blog_posts SET published = status WHERE status IN ('draft', 'published');
UPDATE blog_posts SET published = 'published' WHERE status NOT IN ('draft', 'published', 'scheduled');

